// Prepare the enriched query for the 3 RAG agents
// Input: output from Query Generator agent
const queryGenOutput = $json.output || $json.text || '';
const trigger = $('Execute Workflow Trigger').first().json;

return [{
  json: {
    enriched_query: queryGenOutput,
    tema_semanal: trigger.tema_semanal,
    angulo_enfoque: trigger.angulo_enfoque,
    idioma: trigger.idioma,
    site_id: trigger.site_id
  }
}];

// Consolidate 3 RAG outputs + original payload into a single Writer input
const ragItems = $input.all();
const trigger = $('Execute Workflow Trigger').first().json;

// Extract agent outputs (each agent returns its result in .output or .text)
const coreData = ragItems[0]?.json?.output || ragItems[0]?.json?.text || '{"hechos_clave_extraidos":[]}';
const hermanos = ragItems[1]?.json?.output || ragItems[1]?.json?.text || '{"articulos_hermanos_relevantes":[]}';
const claims   = ragItems[2]?.json?.output || ragItems[2]?.json?.text || '{"claims_antitesis":[],"metadata_busqueda":{}}';

// Build comprehensive writer input message
const writerInput = `
═══════════════════════════════════════════════
TEMA SEMANAL: ${trigger.tema_semanal}
ÁNGULO DE ENFOQUE: ${trigger.angulo_enfoque}
IDIOMA: ${trigger.idioma === 'es' ? 'Español neutro' : 'English'}
SITIO: ${trigger.publisher_name} (${trigger.wp_url})
═══════════════════════════════════════════════

=== SECCIÓN 1: DATOS CORE (Base de Conocimiento Técnica) ===
${coreData}

=== SECCIÓN 2: ARTÍCULOS HERMANOS (Para Interlinking) ===
${hermanos}

=== SECCIÓN 3: ANTÍTESIS Y CLAIMS ADVERSARIALES ===
${claims}

═══════════════════════════════════════════════
INSTRUCCIÓN FINAL:
Usando TODA la información anterior como contexto verificado, genera el artículo completo en formato JSON según las instrucciones de tu System Prompt.
- Integra mínimo 3 interlinks de la Sección 2.
- Integra mínimo 1 bloque de antítesis de la Sección 3.
- Cada dato estadístico DEBE tener respaldo en la Sección 1 o 3.
═══════════════════════════════════════════════
`.trim();

return [{
  json: {
    writer_input: writerInput,
    // Pass through all original trigger data for downstream nodes
    ...trigger
  }
}];

// Parse Director de Arte output and prepare prompt for native Gemini Image node
const directorOutput = $json.output || $json.text || '{}';
const prev = $('Set - Extract Output & Creds').first().json;

let parsed;
try {
  // Try to parse as JSON (Director should return JSON)
  const cleanText = directorOutput
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleanText);
} catch (e) {
  // Fallback: use the raw text as the prompt
  parsed = {
    final_prompt: directorOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()
  };
}

// Build the final prompt — prioritize final_prompt, then compose from parts
const finalPrompt = parsed.final_prompt 
  || [
    parsed.scene_description || '',
    parsed.style_keywords || '',
    parsed.aspect_ratio || 'aspect ratio 16:9'
  ].filter(Boolean).join(', ');

if (!finalPrompt || finalPrompt.length < 10) {
  throw new Error('Director de Arte no generó un prompt válido. Output recibido: ' + directorOutput.substring(0, 200));
}

// Output: the Gemini native node reads $json.image_prompt
return [{
  json: {
    image_prompt: finalPrompt,
    // Pass through all article + WP data for downstream nodes
    ...prev
  }
}];

// ═══ Upload Media to WordPress ═══
// FIX: Manual Authorization header (this.helpers.httpRequest ignores auth object)

const items = $input.all();
const item = items[0];
const creds = $('Execute Workflow Trigger').first().json;
const imgData = $('Code - Extract Image Prompt').first().json;

// --- Build filename ---
const slug = imgData.slug_generado || 'featured';
const siteId = creds.site_id || 'everest';
const filename = `${siteId}-${slug}-${Date.now()}.png`;

// --- Get binary image data ---
let imageBuffer;
if (item.binary && item.binary.data) {
  imageBuffer = Buffer.from(item.binary.data.data, 'base64');
} else {
  throw new Error('No binary data from Gemini. Verify "Generate an image" node config.');
}

// --- Build Basic Auth header manually ---
const wpUrl = creds.wp_url.replace(/\/$/, '');
const authHeader = 'Basic ' + Buffer.from(creds.wp_user + ':' + creds.wp_app_password).toString('base64');

try {
  const uploadResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${wpUrl}/wp-json/wp/v2/media`,
    headers: {
      'Content-Disposition': `attachment; filename="${filename}"`,
      'Content-Type': 'image/png',
      'Authorization': authHeader
    },
    body: imageBuffer,
    returnFullResponse: false
  });

  const mediaId = uploadResponse.id || null;
  if (!mediaId) {
    throw new Error('WP upload response has no media ID: ' + JSON.stringify(uploadResponse).substring(0, 300));
  }

  return [{
    json: {
      media_id: mediaId,
      media_url: uploadResponse.source_url || '',
      filename: filename
    }
  }];

} catch (error) {
  throw new Error(`WordPress media upload failed for ${creds.site_id}: ${error.message}`);
}

// ═══ Create WordPress Post ═══
// FIX: Manual Authorization header (this.helpers.httpRequest ignores auth object)

const uploadResult = $json;
const creds = $('Execute Workflow Trigger').first().json;
const articleData = $('Set - Extract Output & Creds').first().json;

const wpUrl = creds.wp_url.replace(/\/$/, '');
const authHeader = 'Basic ' + Buffer.from(creds.wp_user + ':' + creds.wp_app_password).toString('base64');

// --- Parse tags ---
let tags = articleData.tags_sugeridos_array;
if (typeof tags === 'string') {
  try { tags = JSON.parse(tags); } catch(e) { tags = []; }
}

// --- Build post body ---
const postBody = {
  title: articleData.titulo_generado,
  content: articleData.cuerpo_articulo_html,
  slug: articleData.slug_generado,
  status: 'future',
  date: articleData.wp_scheduled_date,
  featured_media: uploadResult.media_id || 0
};

try {
  const postResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${wpUrl}/wp-json/wp/v2/posts`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': authHeader
    },
    body: postBody,
    returnFullResponse: false
  });

  const postId = postResponse.id || null;
  if (!postId) {
    throw new Error('WP create post response has no ID: ' + JSON.stringify(postResponse).substring(0, 300));
  }

  return [{
    json: {
      post_id: postId,
      post_url: postResponse.link || '',
      media_id: uploadResult.media_id,
      titulo_seo: articleData.titulo_seo_generado,
      meta_descripcion: articleData.meta_descripcion_generada,
      tags_array: tags,
      preguntas_frecuentes: articleData.preguntas_frecuentes_array,
      site_id: creds.site_id
    }
  }];

} catch (error) {
  throw new Error(`WordPress post creation failed for ${creds.site_id}: ${error.message}`);
}

// ═══ PATCH RankMath SEO ═══
// FIX: Manual Authorization header (this.helpers.httpRequest ignores auth object)

const prevData = $json;
const creds = $('Execute Workflow Trigger').first().json;

const wpUrl = creds.wp_url.replace(/\/$/, '');
const authHeader = 'Basic ' + Buffer.from(creds.wp_user + ':' + creds.wp_app_password).toString('base64');
const postId = prevData.post_id;

if (!postId) {
  throw new Error('No post_id available for RankMath PATCH.');
}

// --- Parse FAQ ---
let faq = prevData.preguntas_frecuentes;
if (typeof faq === 'string') {
  try { faq = JSON.parse(faq); } catch(e) { faq = []; }
}

// --- Build tags for focus keyword ---
let tagsArray = prevData.tags_array;
if (typeof tagsArray === 'string') {
  try { tagsArray = JSON.parse(tagsArray); } catch(e) { tagsArray = []; }
}
const focusKeyword = Array.isArray(tagsArray) ? tagsArray.slice(0, 3).join(', ') : '';

// --- PATCH RankMath meta ---
const patchBody = {
  meta: {
    rank_math_title: prevData.titulo_seo || '',
    rank_math_description: prevData.meta_descripcion || '',
    rank_math_focus_keyword: focusKeyword
  },
  featured_media: prevData.media_id || 0
};

try {
  const patchResponse = await this.helpers.httpRequest({
    method: 'PATCH',
    url: `${wpUrl}/wp-json/wp/v2/posts/${postId}`,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': authHeader
    },
    body: patchBody,
    returnFullResponse: false
  });

  return [{
    json: {
      success: true,
      post_id: postId,
      post_url: patchResponse.link || '',
      site_id: prevData.site_id || creds.site_id,
      seo_title: prevData.titulo_seo,
      seo_description: prevData.meta_descripcion,
      focus_keyword: focusKeyword,
      message: `${creds.site_id}: Post #${postId} published with SEO`
    }
  }];

} catch (error) {
  throw new Error(`RankMath PATCH failed for ${creds.site_id} post #${postId}: ${error.message}`);
}
